export interface FormLabelOptions {
  text: string;
  isRequired?: boolean;
  for?: string;
}

/**
 * Creates a <label> element with correct BEM class and accessible markup.
 * The consuming component inserts it before its field element.
 *
 * Required indicator is a separate <span> with aria-hidden so screen readers
 * rely on aria-required on the input instead of the visual asterisk.
 */
export function createFormLabel(options: FormLabelOptions): HTMLLabelElement {
  const label = document.createElement('label');
  label.className = 'o9ds-form-lbl';

  if (options.for) {
    label.setAttribute('for', options.for);
  }

  const textNode = document.createTextNode(options.text);
  label.appendChild(textNode);

  if (options.isRequired) {
    label.classList.add('o9ds-form-lbl--required');
    const asterisk = document.createElement('span');
    asterisk.className = 'o9ds-form-lbl__req';
    asterisk.setAttribute('aria-hidden', 'true');
    asterisk.textContent = '*';
    label.appendChild(asterisk);
  }

  return label;
}

/**
 * Updates an existing label's text and/or required state without re-creating it.
 */
export function updateFormLabel(
  label: HTMLLabelElement,
  options: Partial<FormLabelOptions>
): void {
  if (options.text !== undefined) {
    label.childNodes[0].textContent = options.text;
  }
  if (options.isRequired !== undefined) {
    label.classList.toggle('o9ds-form-lbl--required', options.isRequired);
    const existing = label.querySelector('.o9ds-form-lbl__req');
    if (options.isRequired && !existing) {
      const asterisk = document.createElement('span');
      asterisk.className = 'o9ds-form-lbl__req';
      asterisk.setAttribute('aria-hidden', 'true');
      asterisk.textContent = '*';
      label.appendChild(asterisk);
    } else if (!options.isRequired && existing) {
      existing.remove();
    }
  }
}
